<script>
// SHAHI COUNTER LOGIC - SMOOTH & PREMIUM
const runShahiCountersV5 = () => {
 const counts = document.querySelectorAll('.shahi-count-v5');
 counts.forEach(counter => {
 const target = +counter.getAttribute('data-target');
 let current = 0;
 const increment = target / 100; 
 
 const update = () => {
 if (current < target) {
 current = Math.ceil(current + increment);
 counter.innerText = current > target ? target : current;
 setTimeout(update, 20);
 }
 };
 update();
 });
};

// TRIGGERS ONLY ON SCROLL
const shahiObserverV5 = new IntersectionObserver((entries) => {
 entries.forEach(entry => {
 if(entry.isIntersecting) {
 runShahiCountersV5();
 shahiObserverV5.unobserve(entry.target); 
 }
 });
}, { threshold: 0.5 });

shahiObserverV5.observe(document.getElementById('shahi-trigger-zone-v5'));
</script>","_element_width":"inherit","_flex_align_self":"center"},"elements":[],"widgetType":"html"},{"id":"325eede1","elType":"widget","settings":{"html":"<link href="https://fonts.googleapis.com/css2?family=Libre+Baskerville:wght@400;700&display=swap" rel="stylesheet">

