 color: var(--ceo-black) !important;
 max-width: 1200px;
 margin: 0 auto;
 padding: 0 0 50px 0;
 text-transform: uppercase !important;
 }

 /* 👑 SHAHI AUTHORITY BAR */
 .authority-bar {
 background: var(--ceo-black);
 color: var(--ceo-gold);
 padding: 25px 15px;
 display: flex;
 flex-wrap: wrap;
 justify-content: center;
 gap: 25px;
 border-bottom: 8px solid var(--ceo-gold);
 }
 .auth-item { font-size: 10px; font-weight: 700; display: flex; flex-direction: column; align-items: center; text-align: center; max-width: 165px; }
 .auth-item i { font-size: 24px; margin-bottom: 8px; }
 .auth-item small { font-weight: 400; color: #ccc; margin-top: 5px; font-style: italic; text-transform: none; line-height: 1.4; }

 /* 🏢 CORPORATE HEADER */
 .brand-header { text-align: center; padding: 70px 25px; background: var(--ceo-grey); margin-bottom: 40px; border-bottom: 1px solid #ddd; }
 .brand-tagline { color: var(--ceo-gold); font-size: 16px; font-weight: 700; letter-spacing: 8px; display: block; margin-bottom: 15px; }
 .brand-main-name { font-size: clamp(28px, 7vw, 56px); font-weight: 700; margin: 20px 0; letter-spacing: 1px; color: var(--ceo-black); }

 /* 🎓 STRATEGIC DIVISIONS (EXPANDED CONTENT) */
 .section-title { background: var(--ceo-black); color: var(--ceo-gold); padding: 22px; font-size: 22px; font-weight: 700; text-align: center; letter-spacing: 5px; margin: 60px 25px 40px 25px; border-radius: 4px; border: 1px solid var(--ceo-gold); }
 .grid-container { display: grid; grid-template-columns: repeat(auto-fit, minmax(360px, 1fr)); gap: 25px; padding: 0 25px; }
 .ceo-card { border: 1px solid #eee; padding: 45px; transition: 0.4s cubic-bezier(0.165, 0.84, 0.44, 1); background: var(--ceo-white); border-top: 8px solid var(--ceo-gold); box-shadow: 0 15px 35px rgba(0,0,0,0.05); }
 .ceo-card:hover { background: var(--ceo-black); color: #fff !important; transform: translateY(-12px); border-top-color: #fff; }
 .ceo-card h3 { font-size: 17px; font-weight: 700; margin-bottom: 18px; border-bottom: 2px solid var(--ceo-gold); padding-bottom: 12px; display: inline-block; }
 .ceo-card p { font-size: 14px; text-transform: none !important; line-height: 1.9; font-weight: 400; color: inherit; }

 /* 🚨 MINDSET PROTOCOL */
 .mindset-wrapper { display: grid; grid-template-columns: 1fr; gap: 30px; padding: 0 25px; }
 @media (min-width: 992px) { .mindset-wrapper { grid-template-columns: 1fr 1fr; } }
 .mindset-box { padding: 50px; border: 1px solid #eee; border-radius: 8px; position: relative; }
 .box-reject { border-left: 15px solid var(--danger); background: #fffafa; }
 .box-invite { border-left: 15px solid var(--success); background: #fafffa; }
 .mindset-box b { font-size: 22px; display: block; margin-bottom: 25px; letter-spacing: 1px; color: var(--ceo-black); }
 .mindset-list { font-size: 15px; text-transform: none !important; line-height: 2.4; font-weight: 700; list-style: none; padding: 0; color: #333; }

 /* 🔗 LINK ARCHITECTURE (ALL 16+ ASSETS) */
 .link-header { background: #111; color: var(--ceo-gold); padding: 22px; font-size: 16px; font-weight: 700; margin: 55px 25px 0 25px; letter-spacing: 3px; text-align: center; border: 1px solid var(--ceo-gold); }
 .links-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(300px, 1fr)); gap: 15px; padding: 35px 25px; }
 .btn-ceo { background: #fff; color: var(--ceo-black) !important; text-decoration: none; border: 2px solid #ddd; padding: 22px; font-weight: 700; font-size: 13px; display: flex; justify-content: space-between; align-items: center; transition: 0.3s; border-radius: 4px; }
 .btn-ceo:hover { background: var(--ceo-black); color: var(--ceo-gold) !important; border-color: var(--ceo-gold); }
 .btn-high-action { background: var(--ceo-gold); color: #fff !important; border: none; box-shadow: 0 5px 15px rgba(212, 175, 55, 0.4); }

 .footer-empire { text-align: center; margin-top: 110px; font-weight: 700; color: var(--ceo-black); letter-spacing: 15px; opacity: 0.2; border-top: 2px solid #eee; padding-top: 50px; font-size: 35px; }
</style>

